You want to implement a cache where each index file has its own cache, so when old data and index files are removed, the corresponding cache is also removed. This approach ensures that the cache size remains in sync with the data size.

Here's a basic example of how you can implement this using Python:

```python
import os
import pickle

class IndexCache:
    def __init__(self, cache_dir):
        self.cache_dir = cache_dir
        os.makedirs(cache_dir, exist_ok=True)

    def get(self, index_name):
        cache_file = os.path.join(self.cache_dir, f"{index_name}.cache")
        if os.path.exists(cache_file):
            with open(cache_file, "rb") as f:
                return pickle.load(f)
        return None

    def set(self, index_name, value):
        cache_file = os.path.join(self.cache_dir, f"{index_name}.cache")
        with open(cache_file, "wb") as f:
            pickle.dump(value, f)

    def delete(self, index_name):
        cache_file = os.path.join(self.cache_dir, f"{index_name}.cache")
        if os.path.exists(cache_file):
            os.remove(cache_file)

# Usage
