// Custom Hook file: useNotification.ts
import { createContext, useContext, useState, useEffect } from 'react';

// Create a context for notification
const NotificationContext = createContext(null);

// Define the type for notification props
export type NotificationProps = {
  heading: string;
  subheading: string;
  type: string;
};

// Custom hook to handle notification
export const useNotification = () => {
  const [notificationElement, setNotificationElement] = useState<HTMLElement | null>(null);

  useEffect(() => {
    const element = document.querySelector('huel-notification');
    if (element) {
      setNotificationElement(element);
    }
  }, []);

  const notify = async (props: NotificationProps) => {
    if (!notificationElement) return;

    const { heading, subheading, type } = props;
    await notificationElement.open({
      heading,
      subheading,
      type,
    });
  };

  return { notificationElement, notify };
};
